class Solution:
    def __init__(self):
        self.head = None
        self.tail = None

    def enqueue(self, x):
        if not self.head:
            self.head = self.tail = Node(x)
        else:
            self.tail.next = Node(x)
            self.tail = self.tail.next

    def dequeue(self):
        if not self.head:
            return
        if self.head == self.tail:
            self.head = self.tail = None
        else:
            self.head = self.head.next

        return self.head

# Helper class to represent a Node in the doubly linked list
class Node:
    def __init__(self, value):
        self.value = value
        self.next = None

    def __repr__(self):
        return f'Node({self.value})
'
